import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

// CACHÉ MANUAL
const cacheBusqueda = {};

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor'); 

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const abortControllerRef = useRef(null);
  const statsRef = useRef(null);

  // CARGA DE DATOS
  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) {
      console.error("Error en carga:", error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(() => cargarDatos(), 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // LÓGICA DE BÚSQUEDA
  const ejecutarBusqueda = async (texto) => {
    if (texto.trim() === '') {
      cargarDatos();
      return;
    }
    if (cacheBusqueda[texto]) {
      setProductos(cacheBusqueda[texto]);
      return;
    }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();

    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/buscar?q=${texto}`,
        { signal: abortControllerRef.current.signal }
      );
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) {
      if (err.name !== 'CanceledError') console.error(err);
    }
  };

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => {
        clearTimeout(timeout);
        timeout = setTimeout(() => fn(...args), delay);
      };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [cargarDatos]); 

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol);
      }
    } catch (e) { alert("Error de login"); }
  };

  const handleRegister = async () => {
    try {
      await axios.post('http://localhost:5000/api/register', { 
        usuario, clave: password, rol: nuevoRol 
      });
      alert("Registro exitoso");
      setIsRegisterMode(false);
    } catch (e) { alert("Error al registrar"); }
  };

  const guardarProducto = async () => {
    const data = {
      nombre: nuevoProd.nombre,
      categoria: "General",
      stock: Number(nuevoProd.stock),
      precio_compra: 0,
      precio_venta: Number(nuevoProd.precio_venta),
      fecha_caducidad: null
    };
    if (editMode) {
      await axios.put(`http://localhost:5000/api/productos/${selectedId}`, data);
    } else {
      await axios.post('http://localhost:5000/api/productos', data);
    }
    setShowForm(false);
    setEditMode(false);
    setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    Object.keys(cacheBusqueda).forEach(k => delete cacheBusqueda[k]);
    cargarDatos();
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- VISTA DE LOGIN TOTALMENTE REDISEÑADA ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-gray-100">
          <div className="text-center mb-8">
            <div className="bg-indigo-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-indigo-200">
              <i className="fas fa-store text-white text-2xl"></i>
            </div>
            <h2 className="text-2xl font-bold text-gray-800">{isRegisterMode ? 'Crear cuenta' : '¡Bienvenido!'}</h2>
            <p className="text-gray-500 text-sm mt-1">{isRegisterMode ? 'Regístrate para gestionar tu tienda' : 'Ingresa tus datos para continuar'}</p>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Usuario</label>
              <input 
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                placeholder="Nombre de usuario" 
                onChange={e => setUsuario(e.target.value)} 
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Contraseña</label>
              <input 
                type="password" 
                className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                placeholder="••••••••" 
                onChange={e => setPassword(e.target.value)} 
              />
            </div>
            {isRegisterMode && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Rol</label>
                <select 
                  className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition bg-white"
                  value={nuevoRol} 
                  onChange={e => setNuevoRol(e.target.value)}
                >
                  <option value="vendedor">Vendedor</option>
                  <option value="admin">Administrador</option>
                </select>
              </div>
            )}
            <button 
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-lg transition-all shadow-lg shadow-indigo-100 mt-2"
              onClick={isRegisterMode ? handleRegister : handleLogin}
            >
              {isRegisterMode ? 'Registrarse' : 'Entrar al Sistema'}
            </button>
            <p 
              className="text-center text-sm text-indigo-600 font-medium cursor-pointer hover:underline mt-4"
              onClick={() => setIsRegisterMode(!isRegisterMode)}
            >
              {isRegisterMode ? '¿Ya tienes cuenta? Inicia sesión' : '¿No tienes cuenta? Regístrate'}
            </p>
          </div>
        </div>
      </div>
    );
  }

  // --- VISTA PRINCIPAL (DASHBOARD E INVENTARIO) ---
  return (
    <div className="min-h-screen bg-gray-50 text-gray-800">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} />

      {/* Línea de carga superior */}
      {loading && <div className="h-1 w-full bg-indigo-100 fixed top-0 z-50 overflow-hidden"><div className="h-full bg-indigo-600 animate-[loading_1.5s_infinite]"></div></div>}

      <main className="max-w-7xl mx-auto px-4 py-8">
        {view === "dashboard" ? (
          <div className="space-y-8 animate-in fade-in duration-500">
            <header>
              <h1 className="text-3xl font-bold text-gray-900">Resumen del Negocio</h1>
              <p className="text-gray-500">Aquí tienes un vistazo rápido de tu inventario.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6" ref={statsRef}>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center space-x-4">
                <div className="bg-red-50 p-4 rounded-xl text-red-600"><i className="fas fa-exclamation-triangle text-xl"></i></div>
                <div>
                  <p className="text-sm text-gray-500 font-medium uppercase tracking-wider">Bajo Stock</p>
                  <p className="text-2xl font-bold">{stats.bajo_stock}</p>
                </div>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center space-x-4">
                <div className="bg-blue-50 p-4 rounded-xl text-blue-600"><i className="fas fa-box text-xl"></i></div>
                <div>
                  <p className="text-sm text-gray-500 font-medium uppercase tracking-wider">Total Productos</p>
                  <p className="text-2xl font-bold">{stats.total_productos}</p>
                </div>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center space-x-4">
                <div className="bg-green-50 p-4 rounded-xl text-green-600"><i className="fas fa-dollar-sign text-xl"></i></div>
                <div>
                  <p className="text-sm text-gray-500 font-medium uppercase tracking-wider">Valor Inventario</p>
                  <p className="text-2xl font-bold">${stats.valor_inventario.toLocaleString()}</p>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden animate-in zoom-in-95 duration-300">
            {/* Controles de la Tabla */}
            <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <button 
                  className={`px-6 py-2 rounded-lg font-bold transition flex items-center justify-center gap-2 ${showForm ? 'bg-gray-100 text-gray-600' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-100'}`}
                  onClick={() => { setShowForm(!showForm); setEditMode(false); }}
                >
                    {showForm ? <><i className="fas fa-times"></i> Cancelar</> : <><i className="fas fa-plus"></i> Nuevo Producto</>}
                </button>
                <div className="relative">
                  <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
                  <input
                      type="text"
                      placeholder="Buscar producto..."
                      value={busqueda}
                      onChange={handleBusquedaChange}
                      className="pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none w-full md:w-80 transition"
                  />
                </div>
            </div>

            {/* Formulario Estilizado */}
            {showForm && (
              <div className="p-6 bg-gray-50 border-b border-gray-100 grid grid-cols-1 md:grid-cols-4 gap-4 animate-in slide-in-from-top duration-300">
                  <input className="px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({ ...nuevoProd, nombre: e.target.value })} />
                  <input className="px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({ ...nuevoProd, stock: e.target.value })} />
                  <input className="px-4 py-2 border border-gray-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({ ...nuevoProd, precio_venta: e.target.value })} />
                  <button onClick={guardarProducto} className="bg-green-600 text-white font-bold py-2 rounded-lg hover:bg-green-700 transition shadow-lg shadow-green-100">
                    <i className="fas fa-check mr-2"></i> {editMode ? 'Actualizar' : 'Guardar'}
                  </button>
              </div>
            )}

            {/* Tabla Moderna */}
            <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 border-b border-gray-100">
                      <tr>
                        <th className="px-6 py-4 text-sm font-semibold text-gray-600">Producto</th>
                        <th className="px-6 py-4 text-sm font-semibold text-gray-600">Stock</th>
                        <th className="px-6 py-4 text-sm font-semibold text-gray-600">Precio</th>
                        <th className="px-6 py-4 text-sm font-semibold text-gray-600 text-right">Acciones</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-gray-50 transition">
                          <td className="px-6 py-4 font-medium text-gray-900">{p.nombre}</td>
                          <td className="px-6 py-4">
                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                              {p.stock} unid.
                            </span>
                          </td>
                          <td className="px-6 py-4 font-semibold text-indigo-600">${p.precio_venta}</td>
                          <td className="px-6 py-4 text-right">
                            <div className="flex justify-end gap-2">
                              <button 
                                className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition"
                                onClick={() => { setSelectedId(p.id); setNuevoProd(p); setEditMode(true); setShowForm(true); }}
                              >
                                <i className="fas fa-edit"></i>
                              </button>
                              <button 
                                className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition"
                                onClick={() => eliminar(p.id)}
                              >
                                <i className="fas fa-trash"></i>
                              </button>
                            </div>
                          </td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
